create table if not exists colaboradores (id uuid primary key default gen_random_uuid(),nome text not null,cargo text not null default 'Técnicos',discord_id text unique,aniversario_mes int,aniversario_dia int,ativo boolean default true,created_at timestamptz default now());
create table if not exists pausas (id uuid primary key default gen_random_uuid(),colaborador_nome text not null unique,entrada text,pausa_10_1 text,pausa_20 text,pausa_10_2 text,saida text,updated_at timestamptz default now());
create table if not exists folgas (id uuid primary key default gen_random_uuid(),colaborador_nome text not null,data_folga date not null,motivo text,status text default 'liberada',created_at timestamptz default now());
create table if not exists avisos (id uuid primary key default gen_random_uuid(),canal text not null,titulo text,mensagem text,enviado_em timestamptz default now());
create table if not exists avisos_destinatarios (id uuid primary key default gen_random_uuid(),aviso_id uuid references avisos(id) on delete cascade,colaborador_nome text not null,discord_id text not null,enviado boolean default false,lido boolean default false,enviado_em timestamptz);
alter table colaboradores enable row level security;alter table pausas enable row level security;alter table folgas enable row level security;alter table avisos enable row level security;alter table avisos_destinatarios enable row level security;
create policy "public read colaboradores" on colaboradores for select using (true);create policy "public write colaboradores" on colaboradores for insert with check (true);create policy "public update colaboradores" on colaboradores for update using (true);
create policy "public read pausas" on pausas for select using (true);create policy "public write pausas" on pausas for insert with check (true);create policy "public update pausas" on pausas for update using (true);
create policy "public read folgas" on folgas for select using (true);create policy "public write folgas" on folgas for insert with check (true);
create policy "public read avisos" on avisos for select using (true);create policy "public write avisos" on avisos for insert with check (true);
create policy "public read avisos_destinatarios" on avisos_destinatarios for select using (true);create policy "public write avisos_destinatarios" on avisos_destinatarios for insert with check (true);
